import React from 'react';
import {Modal} from 'react-bootstrap';
import './Modal.css';

const WaitModal = ({show}) => {
    return (
        <Modal
            show={show}
            dialogClassName={'modal-wait'}
        >
            <img
                className={'loading'}
                src={process.env.PUBLIC_URL + '/loading.gif'}
                alt={'loading'}
            />
        </Modal>
    );
}

export default WaitModal;
